package org.apache.spark.sql.delta.test;
/**
 * A helper trait used by test classes that want to collect the scans (i.e. {@link FileSourceScanExec})
 * generated by a given input query during query planning.
 * <p>
 * This trait exposes a single public API {@link getScanReport}.
 */
public  interface ScanReportHelper extends org.apache.spark.sql.test.SharedSparkSession, org.apache.spark.sql.execution.adaptive.AdaptiveSparkPlanHelper {
  /**
   * Collect the scan leaves in the given SparkPlan.
   * @param plan (undocumented)
   * @return (undocumented)
   */
  public  scala.collection.immutable.Seq<org.apache.spark.sql.execution.FileSourceScanExec> collectScans (org.apache.spark.sql.execution.SparkPlan plan)  ;
  /**
   * Returns a new {@link QueryExecutionListener} that can be registered to the Spark listener bus
   * to analyse and collect metrics during query execution.
   * <p>
   * Specifically, this listener will check for any {@link FileSourceScanExec} generated during query
   * planning, cast them into {@link ScanReport} (helper class to hold useful info about the scan), and
   * append to the singleton {@link ScanReportHelper.scans}
   * @return (undocumented)
   */
  public  org.apache.spark.sql.util.QueryExecutionListener getListener ()  ;
  /**
   * Execute function <code>f</code> and return the scans generated during query planning
   * @param f (undocumented)
   * @return (undocumented)
   */
  public  scala.collection.immutable.Seq<org.apache.spark.sql.delta.metering.ScanReport> getScanReport (scala.Function0<scala.runtime.BoxedUnit> f)  ;
}
